const items = $input.all();
const result = [];

for (const item of items) {
  let data = item.json;
  let jsonString = JSON.stringify(data);

  // REGRAS KILLCRITIC DE TEXTO
  jsonString = jsonString.replace(/visita\s*t[ée]cnica/gi, "Avaliação Técnica");
  jsonString = jsonString.replace(/Condfy/gi, "Fortress");
  jsonString = jsonString.replace(/\bDiogo\b/gi, "Tecnólogo Responsável");
  jsonString = jsonString.replace(/\bengenheiro\b/gi, "Tecnólogo Responsável");

  let parsed = JSON.parse(jsonString);

  // REGRA DE RISCO CRÍTICO
  if (parsed.risco && parsed.risco.toLowerCase() === 'crítico' && !parsed.aprovacao_diretoria) {
     parsed.status_aprovacao = "BLOQUEADO - Necessita Aprovação da Diretoria";
     parsed.bloqueio_geracao = true;
  } else {
     parsed.status_aprovacao = "LIBERADO";
     parsed.bloqueio_geracao = false;
  }

  // REGRA DADOS FALTANTES E URGÊNCIA GASTRONÔMICA
  if (parsed.faltam_dados_criticos === true || !parsed.dados_completos) {
     parsed.precificacao_recomendada = "Sob Avaliação Técnica";
     parsed.faixa_comercial = "Sob Avaliação Técnica";
  }

  if (parsed.equipamentos_gastronomia && parsed.equipamentos_gastronomia.length > 0) {
      parsed.fator_urgencia = 1.5; // Alta urgência
  }

  // PROTEÇÃO DE CUSTO INTERNO
  if (parsed.custo_interno !== undefined) delete parsed.custo_interno;
  if (parsed.lucro_bruto !== undefined) delete parsed.lucro_bruto;
  if (parsed.margem_interna !== undefined) delete parsed.margem_interna;

  // REGRA DE IMPOSTOS
  if (parsed.imposto) {
     parsed.imposto_estimado_percentual = parsed.imposto;
     delete parsed.imposto;
  }
  parsed.nota_fiscal = "Imposto baseado em imposto_estimado_percentual - pendente de validação contábil";

  result.push({ json: parsed });
}

return result;

